import React from 'react';
import './Multimedia.css';
import Slideshow from './Slideshow.js';

const headline = 'Rats Orchestrate Takeover of New York City';

class Multimedia extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      max: 10,
      index: 0,
    };
  }

  increase = (direction) => {
    let temp = this.state.index + direction;
    let temp2;
    if (temp == -1) {
      temp = this.state.max;
    } else if (temp == this.state.max + 1) {
      temp = 0;
    }
    this.setState({
      index: temp,
    })
  }

  render() {
    return (
      <div className='Multimedia'>
        <button onClick={() => this.increase(1)}>increase</button>
        <button onClick={() => this.increase(-1)}>decrease</button>
        {this.state.index}


      </div>
    );
  }
}

export default Multimedia;
